arguments.command:
# The BSS symbols are data, not code. Let me check text (code) symbols near those addresses
DBGFILE=/tmp/symbols/libmonosgen-2.0.so.debug

# Get all function (text) symbols and find what contains 0x2f4b20 and 0x2f4c84
llvm-nm-18 --defined-only "$DBGFILE" 2>/dev/null | grep -E "^[0-9a-f]+ [TtWw]" | awk '{print $1, $3}' | sort | awk -v a1="002f4b20" -v a2="002f4c84" -v a3="002c1a40" '
{
  addr = $1
  name = $2
  if (addr <= a1) { prev1_addr = addr; prev1_name = name }
  if (addr <= a2) { prev2_addr = addr; prev2_name = name }
  if (addr <= a3) { prev3_addr = addr; prev3_name = name }
}
END {
  print "0x2f4b20 is in: " prev1_name " @ 0x" prev1_addr
  print "0x2f4c84 is in: " prev2_name " @ 0x" prev2_addr
  print "0x2c1a40 is in: " prev3_name " @ 0x" prev3_addr
}' 2>/dev/null

