arguments.command:
# Check if pin_major_object is a real function in the full symbol table
DBGFILE=/tmp/symbols/libmonosgen-2.0.so.debug
llvm-nm-18 "$DBGFILE" 2>/dev/null | grep "pin_major_object"
echo "---"
# Also check what function symbols are near 0x2c1a40
llvm-nm-18 "$DBGFILE" 2>/dev/null | grep -E "^[0-9a-f]+ [Tt]" | awk '{print $1, $3}' | sort | awk '
{
  if ("0x" $1 + 0 <= 0x2c1a40 + 0) { prev = $2; paddr = $1 }
}
END { print "0x2c1a40 is in: " prev " @ 0x" paddr }'

